UPDATE products
SET stock = stock - {{ $json.cantidad_solicitada }}
WHERE id = {{ $json.product_id }}
RETURNING id AS product_id, sku, stock AS stock_nuevo, (SELECT stock_min FROM products WHERE id = {{ $json.product_id }}) AS stock_min;

UPDATE orders
SET status = 'processing'
WHERE id = {{ $('Registrar Orden').item.json.order_id }};

INSERT INTO pipeline_events (order_id, event_type, status, message, metadata)
VALUES (
  {{ $('Registrar Orden').item.json.order_id }},
  'stock_updated',
  'success',
  'Stock actualizado para {{ $('Actualizar Stock').item.json.sku }} — nuevo stock: {{ $('Actualizar Stock').item.json.stock_nuevo }}',
  jsonb_build_object(
    'sku', '{{ $('Actualizar Stock').item.json.sku }}',
    'stock_anterior', {{ $('Verificar Stock').item.json.stock_actual }},
    'stock_nuevo', {{ $('Actualizar Stock').item.json.stock_nuevo }}
  )
)
RETURNING id AS event_id;

INSERT INTO pipeline_events (order_id, event_type, status, message, metadata)
VALUES (
  {{ $('Registrar Orden').item.json.order_id }},
  'low_stock_alert',
  'warning',
  'ALERTA: Stock bajo para {{ $('Actualizar Stock').item.json.sku }} — stock actual: {{ $('Actualizar Stock').item.json.stock_nuevo }}, mínimo: {{ $('Actualizar Stock').item.json.stock_min }}',
  jsonb_build_object(
    'sku', '{{ $('Actualizar Stock').item.json.sku }}',
    'stock_actual', {{ $('Actualizar Stock').item.json.stock_nuevo }},
    'stock_min', {{ $('Actualizar Stock').item.json.stock_min }}
  )
);

UPDATE orders
SET
  status = 'confirmed',
  processed_at = NOW()
WHERE id = {{ $('Registrar Orden').item.json.order_id }}
RETURNING id AS order_id, order_number, status, processed_at;

UPDATE orders
SET notified_at = NOW()
WHERE id = {{ $('Registrar Orden').item.json.order_id }}
RETURNING id AS order_id, notified_at;

UPDATE orders
SET
  status = 'no_stock',
  processed_at = NOW()
WHERE id = {{ $('Registrar Orden').item.json.order_id }}
RETURNING id AS order_id, order_number, status, processed_at;

INSERT INTO pipeline_events (order_id, event_type, status, message, metadata)
VALUES (
  {{ $('Registrar Orden').item.json.order_id }},
  'stock_checked',
  'warning',
  'Stock insuficiente para {{ $json.sku }} — disponible: {{ $json.stock_actual }}, solicitado: {{ $json.cantidad_solicitada }}',
  jsonb_build_object(
    'sku', '{{ $json.sku }}',
    'stock_disponible', {{ $json.stock_actual }},
    'cantidad_solicitada', {{ $json.cantidad_solicitada }}
  )
);

INSERT INTO pipeline_events (order_id, event_type, status, message, metadata)
VALUES (
  {{ $('Registrar Orden').item.json.order_id }},
  'no_stock_alert',
  'warning',
  'ALERTA: Sin stock para {{ $('Verificar Stock').item.json.sku }} — orden {{ $('Registrar Orden').item.json.order_number }} marcada como no_stock',
  jsonb_build_object(
    'sku', '{{ $('Verificar Stock').item.json.sku }}',
    'order_number', '{{ $('Registrar Orden').item.json.order_number }}',
    'stock_disponible', {{ $('Verificar Stock').item.json.stock_actual }},
    'cantidad_solicitada', {{ $('Verificar Stock').item.json.cantidad_solicitada }}
  )
);

UPDATE orders
SET notified_at = NOW()
WHERE id = {{ $('Registrar Orden').item.json.order_id }}
RETURNING id AS order_id, notified_at;
